import { CallabtSDK, CalibrationEstimate } from 'callabt-sdk';
import React, { useEffect, useState } from 'react';
import CalibrationEstimatePage, { Section } from '../../../view/component/page/CalibrationEstimatePage';
import PageWrapper from '../../../lib/PageWrapper';
import { PageProps } from 'gatsby';

const CalibrationEstimatesId = ({ location }: PageProps) => {
  const params = new URLSearchParams(location.search);
  const id = params.get("id");
  const calibrationEstimateId = Number(id);

  const [sections, setSections] = useState<Section[] | null>(null);

  const fetch = async () => {
    const { calibrationEstimate } = await CallabtSDK.getCalibrationEstimate({ id: calibrationEstimateId });

    const newSections = makeSections(calibrationEstimate);

    setSections(newSections);
  };

  useEffect(() => {
    fetch();
  }, []);

  return (
    <PageWrapper>
      <CalibrationEstimatePage
        sections={sections}
      />
    </PageWrapper>
  );
};

function makeSections(calibrationEstimate: CalibrationEstimate) {
  return [
    {
      title: '견적서',
      infos: [
        {
          title: 'ID',
          description: calibrationEstimate.id,
        },
        {
          title: '요청 날짜',
          description: calibrationEstimate.createdAt,
        },
        {
          title: '제목',
          description: calibrationEstimate.title,
        },
        {
          title: '내용',
          description: calibrationEstimate.contents,
        }
      ]
    },
    {
      title: '요청자',
      infos: [
        {
          title: '이름',
          description: calibrationEstimate.requesterName,
        },
        {
          title: '회사 이름',
          description: calibrationEstimate.companyName,
        },
        {
          title: '회사 주소',
          description: calibrationEstimate.companyAddress,
        },
        {
          title: '연락처',
          description: calibrationEstimate.contact,
        },
        {
          title: '이메일',
          description: calibrationEstimate.email,
        },
      ],
    }
  ]
}

export default CalibrationEstimatesId;

export function Head() {
  return (
    <title>Hello World</title>
  )
}
